INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (26, 2, 'Day 1: After Meeting With Your Guide At The Airport We — Temple', 'moderate', 'After meeting with your guide at the airport we''ll head south reaching the ruined Khmer temple complex of Wat Phou. The first temple on the site was built as early as the 5th century, though the current ruins are from the 11th to 13th centuries. This complex was designated a World Heritage site in 2001. 
Return to Pakse for the night.
Overnight in Pakse', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (27, 2, 'Day 2: The Bolaven Plateau — Waterfall', 'moderate', 'The Bolaven Plateau, located in the Annamite Mountain Range which runs along Laos’ eastern border with Vietnam. The renowned coffee of Lao PDR is produced in this region: the climate of the plateau, with its cooler temperatures and abundant rainfall makes it the perfect place for coffee production. Take time to view several cascading waterfalls -- including the famous Tad Lo and Tad Fan Waterfalls where we will spend the night.
Overnight on the Bolaven Plateau', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (28, 2, 'Day 3: After Breakfast We — Temple', 'moderate', 'After breakfast we''ll head south on a scenic drive to Don Khong. 
On the way we stop at another temple ruin, Wat Tomo.It also contains pre-Angkorian sculptures, in particular a beautiful Mukhalinga (a human-headed linga now located at the Vat Phou Museum).
This island is one of the larger permanent islands in the ‘Si Pan Don’ (4000 Islands) area. We can explore the island on foot or by bicycle. 
Overnight on Don Khong', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (29, 2, 'Day 4: Early In The Morning — Waterfall', 'moderate', 'Early in the morning, we’ll explore Si Pan Don by boat. Here, the Mekong River is at its widest, stretching up to 12 km during the rainy season. As the waters recede, many small islands emerge, giving the region its name. From a distance, you can hear the unmistakable roar of the Li Phi falls, which we will visit.  
We’ll also view the old locomotive and a railway and colonial bridge built by the French in order to avoid navigating the rapids and waterfalls in this section of the Mekong.
Overnight on Don Khone', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (30, 2, 'Day 5: Return By Boat To The Mainland And Visit The Famous Cascade Falls Of Khone Phapheng — Boat', 'moderate', 'Return by boat to the mainland and visit the famous cascade falls of Khone Phapheng. 
After lunch in a nearby restaurant, we''ll continue our journey to the border at Don Kalor. 
From there, you can transfer to Cambodia (or return to Pakse.)
— END OF SERVICES —', 'ACTIVE', NOW());

