INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (151, 7, 'Day 1: Ll Leave Luang Prabang And Take Route — Temple', 'moderate', 'We''ll leave Luang Prabang and take Route 13 through the highlands and breathtaking scenery to Xieng Khouang. On the way we''ll stop to explore one of the many Hmong villages we pass. The small, quiet town of Muang Sui is notable for several reasons. During the Indochina War, this was the last position of the Nationalist Lao Army and the CIA, supported by Air America, before it was evacuated. This area became known as ''Lima Site L-108'' and the runway and some of the abandoned buildings are still visible today. While in Muang Sui we will visit Buddhist sites in the area, including historic temples and caves used as hospitals and shelters during the Indochina wars. 
Overnight in Phonsavan', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (152, 7, 'Day 2: Your Guide Will Take You To Explore The Phonsavan Local Market And An Exhibit Displaying The Huge Va — Market', 'moderate', 'Your guide will take you to explore the Phonsavan local market and an exhibit displaying the huge variety of bombs used during the Indochina War on the way to visit the Plain of Jars. You''ll visit sites 1, 2 & 3 within the Plain of Jars, all of which have been made safe (other areas are considered too dangerous due to remaining unexploded ordnance (UXO).
Overnight in Phonsavan', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (153, 7, 'Day 3: Today We Travel South To The Small Town Of Ban Hahin — Cave', 'moderate', 'Today we travel south to the small town of Ban Hahin. Stopping along the way to visit local Khmu villages and the bustling market of  Lak Sao. Near Konglor cave, surrounded by stunning limestone mountains, is where we will stay for the night.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (154, 7, 'Day 4: Ll Leave Early Today And Head To The Miraculous Kong Lor Cave — Cave', 'challenging', 'We''ll leave early today and head to the miraculous Kong Lor Cave. For 7.5 Kilometers the Hin Bun River makes its way through the mountain forming this stunning cave, we''ll board a local longboat and follow the river through the cave. Using headlamps and torches you can view the stunning stalactites and stalagmites before enjoying a picnic lunch within the Hin Boun National Protected Area. Take time to explore the town and surroundings, relax or maybe trek to the nearby  Nam Sanam waterfall ( only in the rainy season)', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (155, 7, 'Day 5: In The Morning We — Exploration', 'moderate', 'In the morning we''ll continue our journey onwards to Vientiane Capital.
Arrive in afternoon and drop off at your hotel ( accommodation not included)

— END OF SERVICES —', 'ACTIVE', NOW());

