    id, destination_id, sku, title, duration, price,
    summary, hightlight, included, not_included, status, created_at
) VALUES (
    14, 14, NULL, 'Impressions Of Laos',
    '10 DAYS', 2025,
    'Embark on an unforgettable journey through IMPRESSIONS OF LAOS. Experience the authentic culture, stunning landscapes, and warm hospitality of Laos. Your expert guide will take you off the beaten path for a truly immersive adventure.', '• UNESCO World Heritage Sites
• Expert English-speaking guide
• Authentic cultural experiences
• Small group, private service
• All entrance fees included',
    'All sightseeing as described in program above 
Transportation in private AC vehicles 
Accommodation in hotels (twin shared)
English-speaking guide 
Admission fees to sights described above
Meals: B= breakfast, L= lunch, D= dinner
Lao PDR governmental tax and service charge
Luggage handling', 'All sightseeing as described in program above 
Transportation in private AC vehicles 
Accommodation in hotels (twin shared)
English-speaking guide 
Admission fees to sights described above
Meals: B= breakfast, L= lunch, D= dinner
Lao PDR governmental tax and service charge
Luggage handling',
    'ACTIVE', NOW()
