INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (351, 15, 'Day 1: After Transferring On Your Own From Chiang Rai To The Thai — Exploration', 'moderate', 'After transferring on your own from Chiang Rai to the Thai-Lao border crossing at Houay Xai, our guide will meet you at the Lao immigration office and assist you with the visa process. Then we''ll drive to Vieng Phouka, stopping along the way at a Lanten village - the name ''Lanten'' is a Chinese term meaning “the people who dye," as they are known for their natural dye traditions; they''re also one of the few ethnic minorities in Lao PDR who follow Daoism and read Chinese script.
Our journey today will end in Vieng Phouka. a rural village in the heart of northern Laos. Take time to discover the area and meet some of the local people. You''ll spend the night in a local, very basic guesthouse.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (352, 15, 'Day 2: Today We Continue Our Journey On To Luang Namtha — Market', 'moderate', 'Today we continue our journey on to Luang Namtha, heading over the mountain route to take in the stunning views. Upon reaching Luang Namtha take a stroll around the town, visit the busy night market where locals come together to trade goods and handicrafts and also delicious street food.
Overnight in Luang Namtha', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (353, 15, 'Day 3: Ll Embark On — Trek', 'challenging', 'We''ll embark on 3 days of trekking through the forests, fields, rivers and mountains that surround Luang Namtha. Many interesting and challenging treks in this area await you, so you''ll choose among a selection of routes to suit your fitness and stamina. Our guides will then arrange the most interesting route, points of interest and resting points for you. 
Overnight in village homestay', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (354, 15, 'Day 4: Spend Another Day Exploring The Stunninging Nam Ha Protected Area — Exploration', 'moderate', 'Spend another day exploring the stunninging Nam Ha Protected area. Your guide will lead you off the beaten path to discover the natural beauty and wildlife that abounds in this region.
Overnight in village homestay', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (355, 15, 'Day 5: Continue With Your Trekking Adventure In The Wilds Of Luang Namtha — Trek', 'easy', 'Continue with your trekking adventure in the wilds of Luang Namtha. We’ll end the day back at the city in a clean and comfortable room.
Overnight in Luang Namtha', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (356, 15, 'Day 6: Rise Early Like The Locals And Take A Walk To The Local Market — Market', 'moderate', 'Rise early like the locals and take a walk to the local market, where you may see members of hill tribes in traditional clothing buying and selling their products.
After breakfast, you''ll take a private minivan through the countryside to Muang Khua.  You can enjoy the beautiful landscape along the way.  Northern Laos is very ethnically diverse and the mountains surrounding Oudomxay, near the Chinese border, are home to groups like the Akha, Iko, Hmong, Khmu and more.  Despite modernization many of these hill tribes still live traditional lifestyles and follow local and ethnic customs. You''re likely in these regions to see people in beautiful traditional clothing. 
Overnight in Muang Khua', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (357, 15, 'Day 7: The Boat Ride From Muang Khua To Muang Ngoy Winds Through Mountainous Jungle — Boat', 'moderate', 'The boat ride from Muang Khua to Muang Ngoy winds through mountainous jungle. The Nam Ou River, one of the most important in the Lao PDR, offers some of the best scenery. The river runs 448 km from Phongsaly in the north of the country all the way to Luang Prabang where it merges with the Mekong. On board the traditional Lao longtail boat we’ll journey slowly downstream, allowing you to take in the view and relax along the way. The boat will pass many remote villages, rugged mountain terrain and impressive limestone cliffs. We''ll stop at a few of the villages, most of which are only accessible by boat, and get a unique look into traditional daily village life along the river. The day''s journey will end in Muang Ngoy, a relaxing little village where we’ll spend the night.
Overnight in Muang Ngoy', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (358, 15, 'Day 8: After A Short Boat Ride You — Waterfall', 'challenging', 'After a short boat ride you''ll reach the village of Ban Hat Sao, with a mixed population of Lao Lum and Lao Thung. From the village we will follow little trails on a jungle trek through a preserved part of the jungle and into the nearby mountain area. We’ll pass rice fields, forests and agricultural land on our way to the next highlight, a refreshing waterfall. Much of our route follows the stream and we’ll walk through the river and small waterfalls. After an extended break we’ll hike back to the river area. A small walking trail following the Nam Ou River will bring us to Nong Khiaw.
Overnight in Nong Khiaw', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (359, 15, 'Day 9: After A One — Waterfall', 'moderate', 'After a one-hour boat trip on the Nam Ou we''ll start exploring and hiking through the "100 waterfalls," a recently discovered jungle waterfall. A village visit is included as well, where you learn more about life along the Nam Ou River. In the evening we’ll ride back on our boat to Nong Khiaw.
Overnight in Nong Khiaw', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (360, 15, 'Day 10: Ll Drive A Winding Route Following The Nam Ou River Through The Mountains From Nong Khiaw To Luan — Exploration', 'easy', 'We’ll drive a winding route following the Nam Ou River through the mountains from Nong Khiaw to Luang Prabang.  Along the way we''ll visit the village of Ban Nayang, which is famous for its traditional cotton weaving.  Almost every household has its own weaving loom where the families create beautiful scarves, tablecloths and ornate wall hangings. Then we''ll continue to the UNESCO World Heritage City of Luang Prabang, where we''ll take you to your hotel or transfer to Luang Prabang Airport for departure. 
— END OF SERVICES —', 'ACTIVE', NOW());

-- ===== LUXURIOUS LAOS [CLASSIC TOUR (15)] =====
