INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (478, 20, 'Day 3: View The Preparation Of A Lao Meal With A Member Of The Former Royal Court — Temple', 'moderate', 'View the Preparation of a Lao Meal With a Member of the Former Royal Court & Offer It To The Monks.
