INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (626, 26, 'Day 1: Dirt — Boat', 'moderate', '50 km | Dirt & Gravel | Lunch & Dinner
Our adventure begins with a scenic boat crossing over the Mekong River to the peaceful Chomphet side of Luang Prabang. From here, we cycle along gentle dirt and gravel tracks through friendly villages, shady forests, and golden rice fields. With smiling locals, children playing, and buffalo resting in the fields, it feels like stepping into a storybook Laos.
We stop for lunch and a garden visit at the beautiful Green Jungle Park before continuing our ride to Kiao Niao Farmstead — a cosy eco-retreat surrounded by nature. After a delicious home-style dinner, we relax under the stars and enjoy the calm countryside evening.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (627, 26, 'Day 2: Breakfast — Waterfall', 'challenging', 'Breakfast, Lunch & Dinner
After a fresh farm breakfast, we trek to the stunning Kuang Si Waterfalls. Families can enjoy swimming in the bright turquoise pools, relaxing in the shade, or trying the newly built zipline (optional for thrill-seekers!). Lunch is at the View Café overlooking the falls.
On the way back, we visit the Lao Buffalo Dairy — a favourite for both kids and adults! Here you can feed and milk the buffalo, learn about their care, and enjoy tasty ice cream and cheese.
In the afternoon, we take the train to Vang Vieng. Your guide will then invite you for a sunset drink at the rooftop bar of Elephant Crossing Hotel, where hot-air balloons float gently over the valley — a perfect family photo moment.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (628, 26, 'Day 3: Gravel — Exploration', 'moderate', '35 km | Gravel | Breakfast & Lunch
Today is all about fun and water! We cycle easy gravel roads around Vang Vieng, stopping at the famous Blue Lagoons 1, 2, and 3. Each lagoon offers crystal-clear water, rope swings, and shady picnic spots — so don’t forget your swimming costumes!
It’s a relaxed, joyful day with plenty of time to swim, laugh, and enjoy the beautiful river scenery.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (629, 26, 'Day 4: Tarmac — Cave', 'moderate', '20 km | Tarmac | Breakfast & Lunch
After breakfast, we cycle to Kuang Yui Waterfall, hidden in an ancient forest. Here you can see some of Laos’ rarest and oldest trees, marked with orange blessing scarves 
Next, we ride to Tham Cham Cave, where you can float through the cave on an inner tube — an exciting and safe adventure for all ages. The nearby park offers tasty street food and a great river swimming area.
In the late afternoon, we return by train to Luang Prabang, ending our family adventure with wonderful memories.', 'ACTIVE', NOW());

-- ===== THE NORTHERN LOOP [BIKINGCYCLING (30)] =====
INSERT INTO destinations (id, country_id, name, status, created_at) VALUES (27, 1, 'Luang Prabang', 'ACTIVE', NOW()) ON DUPLICATE KEY UPDATE name=VALUES(name);
