INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (751, 31, 'Day 1: We Begin Our Journey By Crossing The Mekong River To Explore The Lesser — Exploration', 'moderate', 'We begin our journey by crossing the Mekong River to explore the lesser-seen Chomphet side of Luang Prabang. The ride follows a mix of dirt and gravel tracks, weaving through rustic villages, serene forest patches, and rice fields. With fewer tourists and plenty of local life unfolding along the way, this ride feels like a step back in time. We finish at Kiao Niao Farmstead, a charming eco-retreat surrounded by greenery, where we enjoy a hearty dinner and a quiet night under the stars.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (752, 31, 'Day 2: After A Farm Breakfast — Exploration', 'moderate', 'After a farm breakfast, we ride towards the emerald cascades of Kuang Si Falls, one of Laos’ most iconic natural wonders. A refreshing dip in the turquoise pools makes for the perfect mid-ride pause. From here, we continue through scenic countryside tracks towards Muang Nan. Later in the afternoon, we transfer by vehicle to Kasi, saving our legs for the climbs to come.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (753, 31, 'Day 3: Today — Exploration', 'moderate', 'Today’s route is smoother, with stretches of brand-new tarmac guiding us deeper into the Lao countryside. The ride feels peaceful and steady, with gentle rolling hills, mountain vistas, and friendly village encounters. We arrive in Muang Met, a quiet town set among farmland and forested hills, perfect for a restful overnight.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (754, 31, 'Day 4: A Big Day Of Adventure Awaits As We Tackle Remote Gravel Roads Leading To Muang Fuang — Boat', 'moderate', 'A big day of adventure awaits as we tackle remote gravel roads leading to Muang Fuang. The route features a serious climb, but the reward is worth every turn of the pedal: sweeping views of limestone cliffs, untouched valleys, and a sense of raw wilderness. This is the kind of cycling day that defines the journey — challenging, but truly memorable.  We will arrange drinks on a boat for sunset on the Nam Lik River', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (755, 31, 'Day 5: Today — Cave', 'moderate', 'Today, we start with a loop around the mountains and a short hike to the viewpoint overlooking the river. We continue on a rugged mix of gravel and patchy tarmac roads, winding our way toward the vibrant town of Vang Vieng. The landscape changes dramatically, with towering karst mountains rising sharply from the valleys. Arriving in Vang Vieng, we’re welcomed by its riverside setting, dramatic scenery, and a more lively atmosphere — the perfect contrast after days in the wild. We will arrive with plenty of time to explore some of the cave complexes close to the town', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (756, 31, 'Day 6: Our Final Day Offers A More Relaxed Pace — Exploration', 'moderate', 'Our final day offers a more relaxed pace. For those who wish, we cycle a scenic gravel loop around Vang Vieng, visiting quiet backroads and swimming holes along the Nam Song River. It’s a light, joyful ride that gives us time to soak in the beauty of the region before gathering for a farewell evening together', 'ACTIVE', NOW());

-- ===== LUANG PRABANG - VIENTIANE [BIKINGCYCLING (30)] =====
INSERT INTO destinations (id, country_id, name, status, created_at) VALUES (32, 1, 'Luang Prabang - Vientiane', 'ACTIVE', NOW()) ON DUPLICATE KEY UPDATE name=VALUES(name);
