INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (801, 33, 'Day 1: Our Journey Begins With A Morning Transfer To The Surreal Buddha Park — Bike', 'moderate', 'Our journey begins with a morning transfer to the surreal Buddha Park, where myth and sculpture meet in a fantastical display of devotion. After time to explore this quirky gem, we hop on our bikes and follow a scenic route through rural backroads and into the rising hills of Phou Khao Khouay.
Lunch awaits at the resort nestled in the forest. The afternoon is yours to soak in the peace, perhaps with a swim in the pool or a walk in the resort’s natural surroundings. The air here feels crisper, and the stars come out in full force.
Cycle: 55 km
Overnight in a jungle resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (802, 33, 'Day 2: After A Peaceful Morning — Exploration', 'moderate', 'After a peaceful morning, we transfer deeper into Laos to Vieng Kham village. From here, our ride begins—meandering through remote settlements and into a landscape carved by time. Our destination is Rock Point, a jagged limestone forest bursting skyward like nature’s own fortress.
Before sunset, we’ll explore the remarkable Karst formations, followed by a local-style dinner with panoramic views over the spiny peaks.
Cycle: 35 km | Transfer: 3 hrs
Overnight in a Cabin with spectacular views', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (803, 33, 'Day 3: Today — Cave', 'moderate', 'Today’s route cuts deep through a limestone valley to one of Laos’ most astonishing wonders—Kong Lor Cave. We trade bikes for wooden boats and enter a 7.5 km underground river, snaking through complete darkness, except for the light of your headlamp and occasional lit-up chambers filled with otherworldly stalactites.
After emerging into the remote hinterlands, we return through the cave and head to Silver River Resort. A light lunch by the water is followed by a peaceful kayaking trip to a jungle lagoon before transferring back to our base.
Cycle: 40 km | Kayak: 1.5 hrs
Overnight in a Cabin with spectacular views', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (804, 33, 'Day 4: This Is A Day Of Descending Thrills And Natural Marvels — Cave', 'moderate', 'This is a day of descending thrills and natural marvels. A short transfer takes us to the mountain top, where we glide downhill through pristine forests. We’ll stop at the Cool Pool, an aquamarine gem perfect for a refreshing dip.
After lunch, we delve into the Dragon Cave, a cavernous hall dripping in stalagmites. A short climb rewards us with panoramic views before riding on to the border town of Lak Sao, humming with Vietnamese trade.
Cycle: 65 km 
Overnight in a local-style guesthouse', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (805, 33, 'Day 5: Our Longest Day Begins From The Guesthouse — Exploration', 'moderate', 'Our longest day begins from the guesthouse, winding over the hills toward Nakai Reservoir. En route, we pause at mountainside Buddha carvings before descending into an eerie flooded forest, ghostly tree trunks standing sentinel over calm waters.
After a lakeside lunch, we roll onward to our peaceful resort beside the vast, mirror-like Nakai Lake. Time slows here as the sun dips behind the water’s edge.
Our guide can grill fresh fish overlooking the lake for our evening meal. 
Cycle: 65 km
Overnight in a Lakeside family resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (806, 33, 'Day 6: Today — Cave', 'moderate', 'Today, we dive into a lush blend of waterfalls, caves, and riverside trails. We start from the resort and walk to Tad Song Sa, a tiered waterfall framed by jungle. After enjoying a smoothie at the top, we continue to Tham Nang Ene Cave, where playful colored lights highlight surreal rock formations.
Lunch is served by the Nam Hinboun River at Tha Falang, a spot popular with local picnickers. Our final ride takes quiet backroads into Thakek, a Mekong-side town with colonial charm and panoramic views of Thailand across the water.
Cycle: 49 km (22 + 27 km) 
Overnight in a Colonial-style Boutique hotel', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (807, 33, 'Day 7: Our Final Ride Follows The Mekong River Before Veering Inland To Khoun Kong Leng Lake — Exploration', 'moderate', 'Our final ride follows the Mekong River before veering inland to Khoun Kong Leng Lake, a hidden, turquoise spring sacred to the locals. It’s the perfect final glimpse of Laos'' raw beauty.
After a farewell lunch, we board the van and begin our return journey to Vientiane, arriving in the capital just after dark, exhilarated and full of unforgettable memories.
Cycle: 50 km
Overnight in a Riverside Boutique hotel', 'ACTIVE', NOW());

