INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (851, 35, 'Day 1: We Arrive In Vientiane And Meet Our Local Guide — Temple', 'moderate', 'We arrive in Vientiane and meet our local guide, ready to gear up with high-quality mountain bikes and dive into our Laotian adventure. Together, we’ll explore the capital’s cultural gems, including the grand Patuxay Monument and the gleaming golden That Luang temple and a visit to the Cope centre, a remarkable Place that openly discusses the issues of development in Laos and the struggles that continue in rural areas after the fallout of the secret war and a relentless 9 year bonbong campaign.
 As evening falls, we’ll gather for a delicious Lao-style feast along the banks of the Mekong River, where the journey ahead takes shape.

 Overnight in Vientiane', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (852, 35, 'Day 2: Our Day Starts Early As We Head Out Toward The Rural Village Of Pak Chom — Exploration', 'moderate', 'Our day starts early as we head out toward the rural village of Pak Chom. From there, we saddle up and begin a scenic ride through lush countryside to Muang Fuang. After a tasty lunch and a few well-earned rest stops, we continue to our serene mountain resort, nestled among soaring karst cliffs, far from the noise of the riverside parties. 
In the evening, it is a short cycle to the shore to unwind at many bars along the Nam Lik Riverbanks.

Overnight in Muang Fuang', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (853, 35, 'Day 3: We Take To The Gravel Trails Today — Boat', 'moderate', 'We take to the gravel trails today, riding a 25 km loop through the breathtaking Fuang Valley. We’ll climb up to the Pha Phou viewpoint, where sweeping views await, and the wind feels like freedom. For lunch, we’ll float down the Namlik River aboard a party boat—yes, a floating feast with music, laughter, and the chance to relax mid-river.
 Overnight in Muang Fuang', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (854, 35, 'Day 4: After Breakfast — Exploration', 'moderate', 'After breakfast, we roll out toward Hinehup on a smooth, newly paved road. A short stretch on the expressway brings us to a stunning lakeside resort perched on the edge of Nam Ngum Lake. Once we’ve refuelled with lunch, we’ll grab kayaks and explore the nearby villages, gliding across calm waters, soaking in the tranquil beauty of this hidden gem.
Overnight in Tha Huae', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (855, 35, 'Day 5: We Transfer To Vang Vieng This Morning To Face The Mighty Big Pha Ngern — Trek', 'challenging', 'We transfer to Vang Vieng this morning to face the mighty Big Pha Ngern. The trek is steep but oh-so-worth it—the panoramic views over Song Valley are simply breathtaking. After descending, we hop on our bikes and head for the famous Blue Lagoons 2 and 3, time to cool off in turquoise waters surrounded by jungle-clad cliffs. We return to the resort refreshed and exhilarated.
Overnight in Tha Huae', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (856, 35, 'Day 6: This Day Is A Dream — Boat', 'moderate', 'This day is a dream. We begin with a peaceful two-hour boat ride across shimmering Nam Ngum Lake—watching the mountains rise, and reflections dance. After arriving at the shore, we make a short transfer before a 2-hour ride to our secluded retreat nestled on the edge of the national park. 
Tonight we sleep with the sounds of the jungle and trickling streams. 
Overnight in Nam Pien Yorla Pa', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (857, 35, 'Day 7: Our Final Day Begins With A Visit To The Laos Conservation Trust — Exploration', 'easy', 'Our final day begins with a visit to the Laos Conservation Trust, where we meet the passionate people protecting the region’s endangered species. As we ride back to Vientiane, the countryside gives us one last show—vibrant rice paddies and the rugged beauty of Phou Khao Khouay in the distance. We call in at the Buddha park on the outskirts of the city. 
Back in the capital, we pause for photos at the Patuxay Monument and gather once more by the Mekong River for our closing meal. Together, we celebrate new friendships, incredible stories, and the adventure of a lifetime.


 Overnight in Vientiane', 'ACTIVE', NOW());

