INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1176, 48, 'Day 1: As We Arrive In The Enchanting Town Of Luang Prabang — Temple', 'easy', 'As we arrive in the enchanting town of Luang Prabang, nestled along the mighty Mekong River, we’re welcomed by serene temples, golden light, and the gentle hum of riverside life. A comfortable hotel awaits us by the water—an ideal spot to unwind and take in the calm flow of this ancient city. In the evening, our guide joins us to check our bikes, and we gather for a welcome dinner at a local restaurant, rich in Lao flavours and warmth.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1177, 48, 'Day 2: Our Journey Begins At The Lao Buffalo Dairy — Exploration', 'moderate', 'Our journey begins at the Lao Buffalo Dairy, where community spirit and creamy cheeses set a joyful tone. From here, we ride along tranquil backroads, past traditional villages and rolling hills, toward the sleepy town of Maung Nan. The route often follows the whispers of the Nam Lik River, offering glimpses of water glistening through bamboo groves. After a riverside lunch, we transfer to Kasi, where small eateries and a cosy guesthouse welcome us.
Cycle: 60 km', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1178, 48, 'Day 3: This Morning — Exploration', 'moderate', 'This morning, we set off through a wide green valley, with towering mountains on either side and the Nam Lik River never far from view. Along the way, we may pass herds of cattle basking on the warm tarmac. Muang Met greets us with its fresh roads and old-world charm. With just a few guesthouses and gracious locals, it’s the kind of place where time seems to pause, perfect for a relaxed evening under the stars.
Cycle: 55 km
Overnight in Muang Met', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1179, 48, 'Day 4: Today — Exploration', 'moderate', 'Today, we climb into the highlands, crossing a remote mountain pass with the help of a local tractor for the steepest bits—a proper Lao-style adventure! As we descend through the village of Nang Po, we stop for a packed lunch, enjoying views of karst peaks rising in the distance. Our final stretch brings us into Muang Fuang, underneath two towering limestone massifs.
Cycle: 55 km
Overnight in a Chalet with a mountain view', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1180, 48, 'Day 5: Before Dawn — Trek', 'challenging', 'Before dawn, we witness a rare and beautiful ritual: long-tail boats glide down the Nam Lik River as monks from local monasteries receive alms and bless the riverside community. After breakfast, we cycle a scenic loop through the Fuang Valley, climbing to the Pha Phou viewpoint for sweeping views over mountains and rice fields. Later, we float downstream on the Nam Lik aboard a longboat—lunch, music, and laughter carried on the current.
Cycle: 25 km | Trek: 3 km
Overnight in a Chaleet with a mountain view', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1181, 48, 'Day 6: We Continue South Along Quiet Gravel Roads — Temple', 'easy', 'We continue south along quiet gravel roads, the Nam Lik River gently guiding our path. Traditional villages dot the landscape, and we stop at a remarkable new temple adorned with 1,000 golden Buddha statues. After lunch in Muang Mon, we transfer to the banks of the Mekong River and journey on to Vientiane. Sunset drinks on the riverbank are the perfect way to celebrate the day''s ride.
Cycle: 65 km 
Overnight in a City Centre Hotel', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1182, 48, 'Day 7: Today We Uncover The Heart Of Laos — Exploration', 'easy', 'Today we uncover the heart of Laos’ capital: the grand Patuxay Monument, the deeply moving COPE Center, and the radiant stupa of That Luang. At the Lao Museum of Art, we admire intricate wood carvings and paintings—echoes of the country''s soul. The Mekong River winds through the city, a constant and calming presence.
Cycle: 25km
Overnight in a City Centre Hotel', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1183, 48, 'Day 8: We Visit The Fascinating Buddha Park — Exploration', 'moderate', 'We visit the fascinating Buddha Park, where whimsical stone sculptures line the riverbank. Then we pedal away from the bustle of the capital, winding through lush countryside toward the picturesque Nam Pien Yorla Pa Resort. Set in forested hills with clear water and open skies, it’s a perfect retreat—and yes, there’s a pool waiting.
Cycle: 55km
Overnight in a Jungle Eco-resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1184, 48, 'Day 9: Today Is Yours To Enjoy At Your Own Pace — Exploration', 'moderate', 'Today is yours to enjoy at your own pace. Explore the on-site Ecology Museum or Wildlife Conservation Centre, zip through the trees on rope courses, or unwind by the pool. The sounds of the forest and flowing water create the perfect soundtrack for rest and renewal.
Overnight in a Jungle Eco-resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1185, 48, 'Day 10: After Breakfast — Boat', 'moderate', 'After breakfast, we ride to the village of Ban Khune before boarding a long-tail boat across a serene lake to our next destination: a lakeside sanctuary surrounded by limestone cliffs and bird calls. As always, the rivers guide us deeper into nature.
Cycle 60km 
Overnight in a lakeside resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1186, 48, 'Day 11: We Transfer To Vang Vieng — Trek', 'challenging', 'We transfer to Vang Vieng, where we lace up for a climb to Big Pha Ngern. The views from the top are jaw-dropping: the Nam Song River winds below through emerald rice paddies and karst peaks. After descending, we hop on bikes to visit the hidden Blue Lagoons 2 and 3—refreshing turquoise pools where we swim and play in the shadow of the jungle.
Cycle 35km Trek 5km 
Overnight in a lakeside resort', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1187, 48, 'Day 12: An Optional Morning Kayak On The Lake Starts The Day — Exploration', 'moderate', 'An optional morning kayak on the lake starts the day, or sleep in and enjoy the peaceful setting. Then we board the scenic train ride back to Luang Prabang. As evening falls, we drift down the Mekong River on a sunset cruise, savouring the golden hour and the gentle rhythm of the water.
Overnight in a luxury hotel', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1188, 48, 'Day 13: A Morning Transfer Takes Us To Long Lao Mai — Trek', 'challenging', 'A morning transfer takes us to Long Lao Mai, a traditional Hmong village. From here, we trek through rice fields and shaded jungle paths to the spectacular Kuang Si Falls. Cool turquoise cascades await! Our bikes are ready nearby for a gentle ride back to Luang Prabang, following winding paths that occasionally reveal glimmers of the Mekong once more.
Cycle 30km Trek 9 km 
Overnight in a luxury hotel', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1189, 48, 'Day 14: Today — Exploration', 'moderate', 'Today, we say goodbye to this beautiful country of rivers, mountains, and unforgettable memories. The Nam Song, Nam Lik, and Mekong have carried us far, but their spirit flows on.', 'ACTIVE', NOW());

-- ===== PAKSE TO SIEM REAP CYCLE VIA 4000 ISLANDS AND PREAH VIHEAR [BIKINGCYCLING (30)] =====
INSERT INTO destinations (id, country_id, name, status, created_at) VALUES (49, 1, 'Pakse to Siem Reap Cycle via 4000 Islands and Prea', 'ACTIVE', NOW()) ON DUPLICATE KEY UPDATE name=VALUES(name);
