INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1291, 52, 'Day 16: Hanoi Free Day — Exploration', 'moderate', 'Hanoi Free Day  (B)
Today you are free at leisure until departure time.', 'ACTIVE', NOW());

