INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1376, 56, 'Day 1: Arrive In Luang Prabang — Market', 'moderate', 'Arrive in Luang Prabang. The Tiger Trail team will be waiting for you in air-conditioned minivans to transfer you to a comfortable hotel/guesthouse in the heart of Luang Prabang. After check-in, we will proceed with local orientation and the health and safety briefing. 
Dinner that evening will be a local hot-pot buffet on the banks of the Mekong river. After dinner, we can explore the night market for essentials needed for the village before returning to the hotel at 9.30 pm.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1377, 56, 'Day 2: Today We Get To Know The Awesome Beautiful City Of Luang Prabang — Temple', 'easy', 'Today we get to know the awesome beautiful city of Luang Prabang, After Breakfast, we start a short hike to the top of Phousi mountain for a view over the city and to learn a little history of the city, we follow with a tour of TEAC the ethnic Minority cultural center to explore the diverse cultural heritage of the area. After some temple hopping and taking in 3 of the most popular and beautiful temples, we break for lunch. 
In the afternoon we will visit the UXO Lao Visitors Center where we will discover Laos Tragic History and the impact of the Second Indochina war on the people and landscape of Laos. 
The afternoon is free to relax and explore before a dinner at Khaiphaen a local Vocational Training Restaurant to learn of the work of Friends International in empowering marginalized youth all over South East Asia.', 'ACTIVE', NOW());
INSERT INTO itineraries (id, tour_id, title, level, description, status, created_at)
VALUES (1378, 56, 'Day 3: Pick Up At Luang Prabang Hotel And Head To The Trekking Drop Off Point In Ban Houay Nok And Tak — Cave', 'challenging', '8.30 Pick up at Luang Prabang Hotel and head to the trekking drop off point in Ban Houay Nok and take a 3-hour trail into the village of Houay Fai
11.30 Arrive in the Village to be greeted by the chief and  homestay families 
